"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import { predictWebcam } from "@/lib/api";
import { RockPaperScissorsGameSection } from "@/section/rock-paper-scissors-game-section";

const POSE_OPTIONS = ["Batu", "Gunting", "Kertas", "Gambar Acak"] as const;
const VALID_POSES = ["Batu", "Gunting", "Kertas"] as const;

type PoseOption = (typeof POSE_OPTIONS)[number];

function getRandomTargetPose(): PoseOption {
  return POSE_OPTIONS[Math.floor(Math.random() * POSE_OPTIONS.length)];
}

function checkMatch(targetPose: PoseOption, prediction: string) {
  if (targetPose === "Gambar Acak") {
    return VALID_POSES.includes(prediction as (typeof VALID_POSES)[number]);
  }

  return prediction === targetPose;
}

export function RockPaperScissorsGameContainer() {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const [targetPose, setTargetPose] = useState<PoseOption>(getRandomTargetPose);
  const [prediction, setPrediction] = useState("");
  const [confidence, setConfidence] = useState<number | null>(null);
  const [isMatch, setIsMatch] = useState(false);
  const [isDetecting, setIsDetecting] = useState(false);
  const [autoCapture, setAutoCapture] = useState(true);
  const [webcamError, setWebcamError] = useState<string | null>(null);
  const [apiError, setApiError] = useState<string | null>(null);

  const captureFrameBase64 = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || video.readyState < video.HAVE_CURRENT_DATA) {
      return null;
    }

    const width = video.videoWidth;
    const height = video.videoHeight;

    if (!width || !height) {
      return null;
    }

    canvas.width = width;
    canvas.height = height;

    const context = canvas.getContext("2d");
    if (!context) {
      return null;
    }

    context.drawImage(video, 0, 0, width, height);
    const dataUrl = canvas.toDataURL("image/jpeg", 0.85);
    return dataUrl.split(",")[1] ?? null;
  }, []);

  const runDetection = useCallback(async () => {
    if (isDetecting || webcamError) {
      return;
    }

    const imageBase64 = captureFrameBase64();
    if (!imageBase64) {
      return;
    }

    setIsDetecting(true);
    setApiError(null);

    try {
      const result = await predictWebcam(imageBase64);
      setPrediction(result.label);
      setConfidence(result.confidence_score);
      setIsMatch(checkMatch(targetPose, result.label));
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : "Terjadi kesalahan saat memanggil API prediksi.";
      setApiError(message);
    } finally {
      setIsDetecting(false);
    }
  }, [captureFrameBase64, isDetecting, targetPose, webcamError]);

  const handleNewChallenge = useCallback(() => {
    setTargetPose(getRandomTargetPose());
    setPrediction("");
    setConfidence(null);
    setIsMatch(false);
    setApiError(null);
  }, []);

  useEffect(() => {
    let isMounted = true;

    async function startWebcam() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: {
            facingMode: "user",
            width: { ideal: 1280 },
            height: { ideal: 720 },
          },
          audio: false,
        });

        if (!isMounted) {
          stream.getTracks().forEach((track) => track.stop());
          return;
        }

        streamRef.current = stream;

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          await videoRef.current.play();
        }

        setWebcamError(null);
      } catch (error) {
        const message =
          error instanceof Error
            ? error.message
            : "Gagal mengakses webcam. Periksa izin kamera Anda.";
        setWebcamError(message);
      }
    }

    startWebcam();

    return () => {
      isMounted = false;
      streamRef.current?.getTracks().forEach((track) => track.stop());
      streamRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!autoCapture || webcamError) {
      return;
    }

    const intervalId = window.setInterval(() => {
      void runDetection();
    }, 1500);

    return () => {
      window.clearInterval(intervalId);
    };
  }, [autoCapture, runDetection, webcamError]);

  return (
    <RockPaperScissorsGameSection
      videoRef={videoRef}
      canvasRef={canvasRef}
      targetPose={targetPose}
      prediction={prediction}
      confidence={confidence}
      isMatch={isMatch}
      isDetecting={isDetecting}
      autoCapture={autoCapture}
      webcamError={webcamError}
      apiError={apiError}
      onToggleAutoCapture={() => setAutoCapture((current) => !current)}
      onDetectPose={() => void runDetection()}
      onNewChallenge={handleNewChallenge}
    />
  );
}
